        "type": null
    },
    {
        "role": "sentence",
        "segment": "Using different terms for the same entity can obscure the understanding of the use case scenarios and their variants, making it harder to ensure consistency and completeness in the requirements.",
        "citations": [
            {
                "type": "source_text",
                "content": "A completely detailed use case specifies all possible variations of each step in the normal scenario, including both valid behaviors and errors.",
